const pesan = ($json.pesan_pengguna || '').toLowerCase();
const konteks = $json.konteks;
let balasan;

if (pesan.includes('risiko tinggi') || pesan.includes('kasus tinggi')) {
  const jumlah = (konteks.cuitanTerbaru || []).filter(c => c.risiko === 'tinggi').length;
  balasan = `Saat ini ada ${jumlah} cuitan contoh dengan klasifikasi risiko tinggi dari model XGBoost. Total keseluruhan (data ringkasan) tercatat ${konteks.ringkasan.risikoTinggi} kasus risiko tinggi dalam 14 hari terakhir.`;
} else if (pesan.includes('akurasi') || pesan.includes('performa') || pesan.includes('model terbaik')) {
  const terbaik = konteks.performaModel.reduce((a, b) => (b.akurasi > a.akurasi ? b : a));
  balasan = `Dari model yang dibandingkan, ${terbaik.model} mencatat akurasi ${(terbaik.akurasi * 100).toFixed(1)}% dan F1-score ${(terbaik.f1 * 100).toFixed(1)}% pada data uji.`;
} else if (pesan.includes('tren') || pesan.includes('minggu') || pesan.includes('hari')) {
  balasan = `Total ${konteks.ringkasan.totalCuitanDianalisis.toLocaleString('id-ID')} cuitan telah dianalisis dalam 14 hari terakhir, dengan ${konteks.ringkasan.risikoSedang} kasus risiko sedang dan ${konteks.ringkasan.risikoTinggi} kasus risiko tinggi.`;
} else if (pesan.includes('halo') || pesan.includes('hai') || pesan.includes('selamat')) {
  balasan = 'Halo! Saya asisten Aurelia. Tanyakan soal jumlah kasus risiko tinggi, performa model, atau tren minggu ini, ya.';
} else {
  balasan = 'Saya bisa membantu menjawab soal jumlah kasus risiko tinggi, performa model, atau tren mingguan. Coba tanyakan salah satu topik itu, ya.';
}

return [{ json: { balasan, sumber: 'n8n-rule-based' } }];
